{
  "domain_analysis": {
    "business_context": "E-commerce platform managing the product catalog, shopping cart, checkout, payment, promotions, and post-sale refund lifecycle. The rules govern inventory reservation timing, promotional discount exclusivity, order immutability after payment, and refund eligibility windows.",
    "bounded_context": "Order & Checkout bounded context, with touchpoints into Inventory, Promotions, and Returns contexts",
    "ubiquitous_language": [
      { "term": "Cart", "definition": "A transient collection of items a customer intends to purchase. Adding items to the cart does NOT reserve inventory." },
      { "term": "Checkout", "definition": "The process initiated when a customer commits to purchasing cart contents. Triggers inventory reservation." },
      { "term": "Inventory Reservation", "definition": "A time-limited hold on inventory units, created when checkout begins, preventing other customers from purchasing the same units. Expires after 15 minutes without payment." },
      { "term": "Reservation Expiry", "definition": "The automatic release of reserved inventory units when a checkout session is abandoned — defined as no payment confirmed within 15 minutes of checkout initiation." },
      { "term": "Promotion", "definition": "A platform-applied pricing discount attached to a specific product. A product may have at most one active promotion at any time." },
      { "term": "Discount Code", "definition": "A customer-supplied code that applies a discount to an order. Mutually exclusive with promotional pricing on the same order." },
      { "term": "Order", "definition": "An immutable record of a completed purchase, created upon payment confirmation. Cannot be modified after payment." },
      { "term": "Payment Confirmation", "definition": "The event marking successful payment processing. After this point the order becomes immutable." },
      { "term": "Refund Window", "definition": "The 30-calendar-day period following delivery during which a customer may request a refund." },
      { "term": "Listed Product", "definition": "A product visible in the catalog. Visibility does not imply purchasability — zero-inventory listed products cannot be bought." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Inventory is NOT reserved when items are added to the cart. Reservation occurs only when checkout begins.",
      "invariant": true,
      "invariant_justification": "Premature reservation would corrupt inventory counts and block other customers from purchasing available stock. The cart-does-not-reserve rule is a core system integrity constraint.",
      "testable_assertion": "Adding an item to a cart must not decrement available inventory or create any reservation record."
    },
    {
      "id": "BR-2",
      "rule": "An inventory reservation must be automatically released if payment is not confirmed within 15 minutes of checkout initiation.",
      "invariant": false,
      "invariant_justification": "The 15-minute window is a business policy threshold. A VP could change it to 10 or 30 minutes without corrupting system state. The principle that abandoned reservations expire IS invariant; the duration is not.",
      "testable_assertion": "Given a checkout started at time T with no payment, at T+15m the reserved inventory units must be returned to available stock and the checkout session invalidated."
    },
    {
      "id": "BR-3",
      "rule": "A product may have at most one active promotion at any given time.",
      "invariant": true,
      "invariant_justification": "Multiple simultaneous promotions on a single product would create ambiguous pricing — the system cannot deterministically resolve which price to display or charge. This is a data consistency invariant.",
      "testable_assertion": "Any attempt to activate a second promotion on a product that already has an active promotion must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Discount codes and promotional pricing are mutually exclusive per order. Only one discount mechanism may apply.",
      "invariant": true,
      "invariant_justification": "Allowing both would result in double-discounting, which corrupts the pricing model and creates financial integrity issues. The system must enforce exactly one discount path.",
      "testable_assertion": "When an order contains a product with an active promotion and a customer applies a discount code, the system must apply only one and reject or override the other — never both."
    },
    {
      "id": "BR-5",
      "rule": "Orders cannot be modified after payment is confirmed.",
      "invariant": true,
      "invariant_justification": "Post-payment order immutability is a financial integrity constraint. Modifications after payment would desynchronize the order record from the actual payment transaction, breaking audit trails and fulfillment accuracy.",
      "testable_assertion": "Any attempt to change line items, quantities, shipping address, or pricing on an order with status 'paid' or beyond must be rejected by the system."
    },
    {
      "id": "BR-6",
      "rule": "A product with zero available inventory cannot be purchased, regardless of catalog listing status.",
      "invariant": true,
      "invariant_justification": "Selling units that do not exist violates physical reality. This is a hard constraint — you cannot fulfill what you do not have. Allowing it would create oversell situations and corrupt inventory state.",
      "testable_assertion": "Checkout initiation or reservation creation must fail for any line item whose product has zero available inventory at the time of the attempt."
    },
    {
      "id": "BR-7",
      "rule": "Refunds must be requested within 30 days of delivery.",
      "invariant": false,
      "invariant_justification": "The 30-day window is a business policy. Management could extend it to 60 days for holiday seasons or shorten it for certain product categories without corrupting system integrity.",
      "testable_assertion": "A refund request submitted more than 30 calendar days after the recorded delivery date must be rejected."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A customer has added 2 units of Product X (5 in stock) to their cart",
      "when": "Another customer queries available inventory for Product X",
      "then": "Available inventory shows 5 units — cart additions do not reduce available count"
    },
    {
      "id": "AC-2",
      "given": "A customer initiates checkout with 2 units of Product X (5 in stock)",
      "when": "The checkout process begins",
      "then": "2 units are reserved, available inventory drops to 3, and a 15-minute expiry timer starts"
    },
    {
      "id": "AC-3",
      "given": "A checkout was initiated 15 minutes ago and payment has not been confirmed",
      "when": "The reservation expiry timer fires",
      "then": "The reserved units are released back to available inventory, and the checkout session is invalidated so it cannot be completed"
    },
    {
      "id": "AC-4",
      "given": "Product X has an active promotion '20% off Summer Sale'",
      "when": "An admin attempts to activate a second promotion 'Buy One Get One' on Product X",
      "then": "The system rejects the second promotion with an error indicating an active promotion already exists"
    },
    {
      "id": "AC-5",
      "given": "A customer's cart contains Product X with an active promotion (20% off) and the customer enters discount code 'SAVE10'",
      "when": "The order total is calculated",
      "then": "Only one discount mechanism is applied — the system must not stack both the promotion and the discount code"
    },
    {
      "id": "AC-6",
      "given": "An order has been paid and confirmed with status 'paid'",
      "when": "Any actor attempts to modify the order (change items, quantities, or shipping details)",
      "then": "The modification is rejected and the order remains unchanged"
    },
    {
      "id": "AC-7",
      "given": "Product Y is listed in the catalog with 0 available inventory",
      "when": "A customer attempts to initiate checkout with Product Y in their cart",
      "then": "Checkout is blocked for that item with a clear message that the product is out of stock"
    },
    {
      "id": "AC-8",
      "given": "An order was delivered on March 1st",
      "when": "The customer submits a refund request on March 30th (day 29)",
      "then": "The refund request is accepted for processing"
    },
    {
      "id": "AC-9",
      "given": "An order was delivered on March 1st",
      "when": "The customer submits a refund request on April 1st (day 31)",
      "then": "The refund request is rejected as outside the 30-day refund window"
    },
    {
      "id": "AC-10",
      "given": "A customer is at the payment step with a valid reservation",
      "when": "Payment is confirmed at exactly 14 minutes and 59 seconds after checkout initiation",
      "then": "The payment succeeds and the reservation is converted to a confirmed order"
    },
    {
      "id": "AC-11",
      "given": "Two customers each have 1 unit of Product Z (1 in stock) in their carts",
      "when": "Both initiate checkout simultaneously",
      "then": "Only one customer successfully reserves the unit; the other receives an out-of-stock error"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Payment confirmation arrives at the exact moment the 15-minute reservation expires",
      "expected_behavior": "The system must handle this race condition atomically. Either the payment succeeds and the reservation is honored, or the reservation has already been released and payment must be rejected with an appropriate error. The system must never both release inventory AND charge the customer."
    },
    {
      "scenario": "A product's last unit is in a reservation that is about to expire while another customer attempts checkout",
      "expected_behavior": "The second customer's checkout must fail until the reservation is actually released. Speculative availability based on expected expiry must not be used."
    },
    {
      "scenario": "Discount code vs. promotion — which one wins when both are present?",
      "expected_behavior": "The spec says only one applies but does not specify which takes precedence or whether the customer chooses. This is an ambiguity that must be resolved. Common patterns: apply whichever gives the customer the better deal, always prefer promotion, or let the customer choose."
    },
    {
      "scenario": "Admin deactivates a promotion on a product while a customer is mid-checkout with that promotional price",
      "expected_behavior": "The price locked at checkout initiation should be honored for the duration of the checkout session. Changing mid-session would violate customer expectations and potentially consumer protection laws."
    },
    {
      "scenario": "Customer requests refund on an order that has not yet been delivered",
      "expected_behavior": "The 30-day refund window starts at delivery, so technically the window hasn't opened yet. The system should either reject with 'order not yet delivered' or route to a cancellation flow instead."
    },
    {
      "scenario": "Partial order refund — customer wants to refund one item from a multi-item order",
      "expected_behavior": "Spec says orders are immutable after payment but does not address partial refunds. This is a gap — refunds likely create a separate return/refund record rather than modifying the original order."
    },
    {
      "scenario": "Inventory drops to zero after items are added to cart but before checkout",
      "expected_behavior": "Since cart does not reserve inventory, checkout initiation must fail with an out-of-stock error. The customer should be informed the item is no longer available."
    },
    {
      "scenario": "Customer applies a discount code to an order where no items have promotions, then an admin activates a promotion on one product before payment",
      "expected_behavior": "The discount code was valid at checkout time. If the system locks pricing at checkout, the discount code applies. The promotion activation should not retroactively affect an in-progress checkout."
    }
  ],

  "business_impact": {
    "financial": "Inventory reservation timing directly affects conversion rates and revenue. Too-short windows lose sales from slow payers; too-long windows block inventory from ready buyers. Discount stacking prevention protects margin integrity. The refund window defines the liability tail on every sale.",
    "operational": "Reservation expiry requires reliable background job processing — failure to release reservations causes phantom stock-outs. Single-promotion-per-product simplifies catalog management and price display logic. Order immutability simplifies fulfillment pipelines by guaranteeing stable order data.",
    "user": "No cart reservation means customers may reach checkout only to find items unavailable — potential frustration. Clear communication of out-of-stock at checkout is critical. The discount exclusivity rule may confuse customers who expect to combine deals. The 30-day refund window sets clear customer expectations.",
    "risk": "Race conditions at reservation boundaries could result in overselling (financial loss, customer trust damage) or phantom stock-outs (lost revenue). Failure to enforce order immutability could create fulfillment/accounting mismatches. Ambiguity in discount precedence could lead to inconsistent customer experiences or margin leakage.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Cart-to-checkout inventory gaps may cause frustration. Discount exclusivity must be clearly communicated to avoid confusion and abandoned carts." },
      { "group": "Merchandising / Marketing", "impact": "Single-promotion constraint requires coordination to avoid conflicts. Must deactivate current promotion before activating a new one." },
      { "group": "Finance / Accounting", "impact": "Order immutability and discount exclusivity protect revenue integrity. Refund window defines financial liability exposure." },
      { "group": "Warehouse / Fulfillment", "impact": "Reservation system directly controls pick/pack signals. Expired reservations must not trigger fulfillment." },
      { "group": "Customer Support", "impact": "Must handle edge cases: expired checkouts, denied discount stacking, refund window boundary disputes. Need clear tooling and policies." },
      { "group": "Platform Engineering", "impact": "Must implement atomic reservation, reliable expiry (exact-once job execution), and race-condition-safe inventory management." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is clear and internally consistent on most rules. Confidence is docked because: (1) the discount precedence rule is ambiguous — 'only one applies' but no priority is specified, (2) the interaction between order immutability and refunds is not fully specified — refunds imply some form of reversal, (3) no specification of what happens to in-flight checkouts when promotions change or inventory is adjusted by admins, (4) partial refund handling is unaddressed.",
    "high_confidence_areas": [
      "Cart does not reserve inventory — unambiguous",
      "Order immutability after payment — clear and enforceable",
      "Zero-inventory blocks purchase — clear physical constraint",
      "One active promotion per product — clear uniqueness constraint"
    ],
    "low_confidence_areas": [
      "Discount code vs. promotion precedence — which wins is unspecified",
      "Price locking semantics during checkout — when exactly is the price frozen?",
      "Refund mechanics vs. order immutability — how are refunds modeled if orders can't be modified?",
      "Partial refund handling — not addressed at all"
    ],
    "assumptions": [
      "The 15-minute reservation window is measured from checkout initiation, not from last user activity",
      "Refund window of 30 days is calendar days, not business days",
      "Order immutability means the order record itself; refunds are modeled as separate entities referencing the original order",
      "Inventory reservation is per-unit and atomic — no partial reservations",
      "Discount exclusivity applies at the order level, not per line item"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "When both a discount code and promotional pricing could apply to an order, the spec says 'only one discount mechanism applies' but does not define precedence. Should the system: (A) apply whichever gives the customer the better price, (B) always prefer the promotion over the discount code, (C) always prefer the discount code, or (D) let the customer choose?",
      "affected_stakeholders": ["Customers", "Marketing", "Finance"],
      "options": [
        "A: Apply the more favorable discount for the customer (customer-friendly, higher margin risk)",
        "B: Promotion always wins (simpler, marketing controls pricing)",
        "C: Discount code always wins (rewards active engagement, code distribution is controlled)",
        "D: Customer chooses at checkout (best UX, most implementation complexity)"
      ],
      "recommendation": "Option D (customer chooses) is the most common e-commerce pattern and maximizes customer trust. If implementation cost is a concern, Option A is the next best choice."
    },
    {
      "type": "ambiguity",
      "description": "The spec states orders are immutable after payment, but also allows refunds within 30 days. How are refunds modeled? If the order cannot be modified, refunds must be separate entities. The spec does not clarify whether partial refunds (single items from multi-item orders) are supported.",
      "affected_stakeholders": ["Customers", "Finance", "Customer Support"],
      "options": [
        "A: Refunds are separate Return entities that reference the original immutable Order",
        "B: Order immutability applies to forward flow only; refunds are a special modification class"
      ],
      "recommendation": "Option A — model refunds as separate Return/Refund aggregate roots referencing the original order. This preserves immutability and maintains clean audit trails."
    },
    {
      "type": "missing_context",
      "description": "No specification of price-locking semantics during the checkout window. If a promotion is added, removed, or prices change during the 15-minute checkout session, does the customer get the price at checkout initiation or the current price at payment time?",
      "affected_stakeholders": ["Customers", "Finance", "Legal"],
      "options": [
        "A: Lock price at checkout initiation — customer sees price, that's what they pay",
        "B: Use current price at payment confirmation — risk of price change surprises"
      ],
      "recommendation": "Option A — lock at checkout initiation. Price changes during an active session violate customer expectations and may breach consumer protection regulations in many jurisdictions."
    }
  ],

  "rejection_reasons": []
}

